var e=[{id:`L2_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`딸꾹.`,JPN:`ひくっ。`,ENG:`*Hic*`,TWN:`嗝嗝。`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`GREMORY_BAR_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`어라? 벌써 다 마셨나?`,JPN:`あれ？　もう飲み切っちゃった？`,ENG:`Hmm? It's gone already?`,TWN:`嗯？都喝完啦？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`GREMORY_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`말도 안 돼…….`,JPN:`バカな……`,ENG:`Impossible...`,TWN:`怎麼可能……`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`MODER_BOSS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`술을 연료로 동작하는 메커니즘인데, 인간에게 흡수력이 밀린다고?`,JPN:`酒を燃料として作動するメカニズムなのに、人間の吸収力に負けてるだなんて？`,ENG:`It was built to use booze as fuel... How can it be beaten by a human?!`,TWN:`它的運作機制是以酒作為燃料，竟然會喝輸人類？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`MODER_BOSS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ff3636>경고. 경고. 동력원 과다 공급.</color>`,JPN:`<color=#ff3636>警告。警告。動力源過剰供給。</color>`,ENG:`<color=#ff3636>Warning. Warning. Power overload.</color>`,TWN:`<color=#ff3636>警告，警告，動能超載。</color>`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`MODER_BOSS_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`내, 내 걸작이 지다니!`,JPN:`わ、私の傑作が負けたなんて！`,ENG:`M-my masterpiece!!`,TWN:`我…我的傑作竟然會輸！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`RESORT_NPC_HAVEN_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`MC_HAVEN_NULL_NULL`,text:{KOREA:`우, 우승자가 탄생했습니다! 실례지만 성함이?`,JPN:`ゆ、優勝者が誕生しました！　失礼ですが、お名前は？`,ENG:`W-we have a winner! Um, excuse me, but what's your name?`,TWN:`贏…贏家出爐啦！不好意思，請問怎麼稱呼？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`MC_HAVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`딸꾹… 사랑의 조언가, 그레모리야.`,JPN:`ひくっ……恋のカウンセラー、グレモリーよ。`,ENG:`*Hic* Gremory, the Love Adviser.`,TWN:`嗝嗝…我是愛情專家 葛茉莉。`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`GREMORY_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`MC_HAVEN_NULL_NULL`,text:{KOREA:`그레모리 씨의 승리입니다!`,JPN:`グレモリーさんの勝利です！`,ENG:`Ms. Gremory is the winner!`,TWN:`獲勝的是葛茉莉小姐！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`MC_HAVEN_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`정말 연약한 로봇이었어. 딸꾹.`,JPN:`本当に弱いロボットだったわ。ひっく。`,ENG:`What a weak robot. *Hic*`,TWN:`這機器人超弱的，嗝～`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`GREMORY_BAR_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`……졌어. 깔끔하게 인정할게. 나도 아직 한참 멀었네.`,JPN:`……負けたわ。潔く認めるよ。私もまだまだってことね。`,ENG:`I lost... I'll admit it. Guess I still have a long way to go.`,TWN:`……我認輸！看來我還差得遠呢。`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`RESORT_NPC_HAVEN_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`RESORT_NPC_HAVEN_NULL`,text:{KOREA:`궁금한 게 있어. 저 아이들이 뭘 준다고 했길래 대신 대결에 나온 거지?`,JPN:`気になることがあるんだけど。あの子たちから何をもらう条件で代わりに対決に出たの？`,ENG:`Lemme ask you a question. What did those kids promise you in exchange?`,TWN:`我有個疑問，她是用什麼東西收買你，讓你願意來代打？`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`RESORT_NPC_HAVEN_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`GREMORY_BAR_NULL_NULL`,text:{KOREA:`왜 이래, 언니~ 그야 당연히 술이지~`,JPN:`何よ、お姉ちゃん～そりゃあ、お酒に決まってるじゃないの～`,ENG:`C'mon, sis! Booze, of course!`,TWN:`怎麼這麼說呢，姊姊～當然就是酒囉～`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:null,C:{char_id:`GREMORY_BAR_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L26_1`,type:`dialog`,speaker:`SWORD_OZ_NULL_NULL`,text:{KOREA:`해냈어! 시그마! 네 덕분이야!`,JPN:`やった！　シグマ！　あなたのおかげだよ！`,ENG:`We did it! Sigma! It's all thanks to you!`,TWN:`成功咧！西格瑪！都是你的功勞！`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`NIGHTMARE_DREAM_SUMMER_NULL`,face:`UNIT_LAUGH`}}}},{id:`L27_1`,type:`dialog`,speaker:`NIGHTMARE_DREAM_SUMMER_NULL`,text:{KOREA:`몸이 깃털처럼 가벼워. 헹가래하기도 쉽네.`,JPN:`身体が羽みたに軽い。胴上げしやすいね。`,ENG:`You're light as a feather. It's so easy to hoist you.`,TWN:`你輕得像羽毛一樣，應該可以把你拋起來吧。`},stage:{bg:`SUMMER_HOTEL_NIGHT`,slots:{L:{char_id:`SWORD_OZ_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`NIGHTMARE_DREAM_SUMMER_NULL`,face:`UNIT_IDLE`}}}}];export{e as default};